import json, sys, re
from collections import Counter
from datetime import datetime, timezone

raw = json.load(sys.stdin)
if isinstance(raw, str):
    raw = json.loads(raw)
if isinstance(raw, dict) and "merged" in raw:
    raw = raw["merged"]

def unwrap(x):
    if isinstance(x, dict) and list(x.keys()) == ["result"]:
        return x["result"]
    if isinstance(x, dict) and "status" in x and "body" in x:
        return x["body"]
    return x

def find_dependents(node):
    """Recursively search any string in the structure for GitHub dependents count."""
    if isinstance(node, str) and len(node) > 100:
        m = re.search(r'([\d,]+)\s+Repositor', node)
        if m:
            return int(m.group(1).replace(",", ""))
    elif isinstance(node, dict):
        for v in node.values():
            r = find_dependents(v)
            if r is not None:
                return r
    elif isinstance(node, list):
        for v in node:
            r = find_dependents(v)
            if r is not None:
                return r
    return None

if isinstance(raw, dict):
    candidates = list(raw.values())
elif isinstance(raw, list):
    candidates = raw
else:
    candidates = [raw]

commits = releases = contributors = stars = None
issues_lists = []
dependents = None

for v in candidates:
    u = unwrap(v)
    if isinstance(u, str):
        try:
            u = json.loads(u)
        except Exception:
            pass
    # Try extracting dependents from any candidate (Playwright HTML)
    if dependents is None:
        dependents = find_dependents(u)
    if isinstance(u, list) and u and isinstance(u[0], dict):
        first = u[0]
        if "sha" in first or "commit" in first:
            commits = u
        elif "contributions" in first and "login" in first:
            contributors = u
        elif "state" in first and "number" in first and "sha" not in first:
            issues_lists.append([i for i in u if "pull_request" not in i])
    elif isinstance(u, dict):
        if "published_at" in u or "tag_name" in u:
            releases = u
        elif "stargazers_count" in u:
            stars = u.get("stargazers_count")
        elif "issues" in u:
            issues_lists.append(u["issues"])
        # Playwright results dict: {"html": "...", ...}
        elif "html" in u or "results" in u:
            if dependents is None:
                dependents = find_dependents(u)

# Combine open and closed issues
issues = []
for lst in issues_lists:
    issues.extend(lst)

if commits is None and not issues and releases is None and contributors is None:
    def describe(x):
        if isinstance(x, dict):
            return {"dict_keys": list(x.keys())[:8]}
        if isinstance(x, list):
            return {"list_len": len(x), "first": describe(x[0]) if x else None}
        return type(x).__name__
    print(json.dumps({"debug": describe(raw)}))
    sys.exit(0)

commits      = commits      or []
releases     = releases     or {}
contributors = contributors or []

BOTS = {"web-flow"}

def parse(ts):
    if not ts:
        return None
    try:
        return datetime.fromisoformat(ts.replace("Z", "+00:00"))
    except Exception:
        return None

def is_bot(login):
    return (not login) or login.endswith("[bot]") or login in BOTS

now = datetime.now(timezone.utc)

# ---- COMMIT VELOCITY ----
dates = [parse(c.get("commit", {}).get("author", {}).get("date")) for c in commits]
dates = [d for d in dates if d]
total_commits = len(commits)
if len(dates) >= 2:
    range_days = max((max(dates) - min(dates)).days, 1)
else:
    range_days = 1
commits_per_week = round(total_commits / (range_days / 7), 2) if total_commits else 0.0

def velocity_score(cpw):
    if cpw > 10: return 90
    if cpw >= 5: return 70
    if cpw >= 2: return 50
    if cpw > 0:  return 30
    return 0
cv_score = velocity_score(commits_per_week)

# ---- BUS FACTOR ----
if contributors and isinstance(contributors[0], dict) and "contributions" in contributors[0]:
    real = [c for c in contributors if not is_bot(c.get("login", ""))]
    real_total = sum(c.get("contributions", 0) for c in real)
    top_raw = sorted(real, key=lambda c: c.get("contributions", 0), reverse=True)[:3]
    top3 = [{"login": c.get("login"), "commit_count": c.get("contributions")} for c in top_raw]
    top_pct = round(top_raw[0].get("contributions", 0) / real_total * 100, 1) if real_total and top_raw else 0.0
else:
    logins = [c.get("author", {}).get("login") for c in commits if c.get("author")]
    logins = [l for l in logins if not is_bot(l)]
    counts = Counter(logins)
    real_total = sum(counts.values())
    top3 = [{"login": l, "commit_count": n} for l, n in counts.most_common(3)]
    top_pct = round(counts.most_common(1)[0][1] / real_total * 100, 1) if real_total else 0.0

def bus_score(p):
    if p < 20: return 90
    if p <= 35: return 70
    if p <= 50: return 50
    if p <= 70: return 30
    return 10
bf_score = bus_score(top_pct) if real_total else 0

# ---- ISSUE HEALTH ----
closed = sum(1 for i in issues if i.get("state", "").upper() == "CLOSED")
open_  = sum(1 for i in issues if i.get("state", "").upper() == "OPEN")
total_issues = closed + open_
close_rate = round(closed / total_issues * 100, 1) if total_issues else 0.0

def close_score(r):
    if r > 70: return 90
    if r >= 50: return 70
    if r >= 30: return 50
    return 30
ic_score = close_score(close_rate) if total_issues else 0

# ---- RELEASE CADENCE ----
pub = parse(releases.get("published_at"))
days_since = (now - pub).days if pub else 9999

def cadence_score(d):
    if d < 30:  return 90
    if d <= 90: return 70
    if d <= 180: return 50
    if d <= 365: return 30
    return 10
rc_score = cadence_score(days_since)

# ---- FAILURE PREDICTION ----
if bf_score > 70 and cv_score > 60:
    burnout = "low"
elif bf_score < 40 or cv_score < 30:
    burnout = "high"
else:
    burnout = "medium"

risk = 0.0
if days_since > 180:   risk += 0.4
elif days_since > 90:  risk += 0.2
if commits_per_week < 2:   risk += 0.4
elif commits_per_week < 5: risk += 0.2
if total_issues and close_rate < 30: risk += 0.2
abandonment = round(min(risk, 1.0), 2)

# ---- CONTRIBUTOR COUNT ----
contributor_count = len([
    c for c in contributors
    if isinstance(c, dict) and not is_bot(c.get("login", ""))
]) if isinstance(contributors, list) else None

result = {
    "commit_velocity": {
        "total_commits_in_sample": total_commits,
        "date_range_days": range_days,
        "commits_per_week": commits_per_week,
        "commit_velocity_trend_score": cv_score,
    },
    "bus_factor": {
        "top_contributor_pct": top_pct,
        "bus_factor_score": bf_score,
        "top_contributors": top3,
    },
    "issue_health": {
        "open_count": open_,
        "closed_count": closed,
        "close_rate_pct": close_rate,
        "issue_close_rate_score": ic_score,
    },
    "release_cadence": {
        "days_since_last_release": days_since,
        "last_release_tag": releases.get("tag_name", ""),
        "release_cadence_score": rc_score,
    },
    "contributor_count": contributor_count,
    "github_stars": stars,
    "github_dependents": dependents,
    "failure_prediction": {
        "maintainer_burnout_risk": burnout,
        "abandonment_probability": abandonment,
    },
}

print(json.dumps(result))
